        "SELECT Organisation_name, CAST(REPLACE(`Total_scope_1_emissions_t_CO2-e`, ',', '') AS BIGINT) as scope1_tonnes FROM danny_catalog.dem_schema.nger_corporate_emissions WHERE `Total_scope_1_emissions_t_CO2-e` != '' AND `Total_scope_1_emissions_t_CO2-e` IS NOT NULL ORDER BY scope1_tonnes DESC LIMIT 15"
      ]
    },
