    },
    {
      "name": "table_count",
      "displayName": "Table Count",
      "queryLines": [
        "SELECT COUNT(DISTINCT table_name) as cnt FROM danny_catalog.information_schema.tables WHERE table_schema = 'dem_schema'"
      ]
    },
    {
      "name": "nger_elec_sector",
      "displayName": "Electricity Sector Emissions",
      "queryLines": [
        "SELECT\n",
        "  State,\n",
        "  Primary_fuel,\n",
        "  Facility_name,\n",
        "  Type,\n",
        "  Grid,\n",
        "  CAST(REPLACE(`Total_scope_1_emissions_t_CO2-e`, ',', '') AS BIGINT) as scope1_tonnes,\n",
        "  CAST(REPLACE(`Electricity_production_MWh`, ',', '') AS BIGINT) as production_mwh\n",
        "FROM\n",
        "  danny_catalog.dem_schema.nger_electricity_sector\n",
        "WHERE\n",
        "  `Total_scope_1_emissions_t_CO2-e` IS NOT NULL\n",
        "  AND `Total_scope_1_emissions_t_CO2-e` != ''\n",
        "  AND State IS NOT NULL\n",
        "  AND State != ''\n",
        "  AND State != '-'\n",
        "  AND Primary_fuel IS NOT NULL\n",
        "  AND Primary_fuel != ''\n",
        "  AND Primary_fuel != '-'"
      ]
    },
    {
      "name": "imports_top_countries",
      "displayName": "Top Import Countries",
      "queryLines": [
        "SELECT\n",
        "  Source_country,\n",
        "  SUM(`Total_oil_imports_ML`) as total_oil_imports_ML,\n",
        "  SUM(`Crude_oil_&_other_refinery_feedstocks_ML`) as crude_oil_ML,\n",
        "  SUM(`Diesel_oil_ML`) as diesel_ML,\n",
        "  SUM(`Aviation_turbine_fuel_ML`) as aviation_fuel_ML,\n",
        "  SUM(`Automotive_gasoline_ML`) as gasoline_ML\n",
        "FROM\n",
        "  danny_catalog.dem_schema.petroleum_imports_by_country\n",
        "WHERE\n",
        "  Source_country IS NOT NULL\n",
        "  AND Source_country != ''\n",
        "  AND Source_country != 'No Country Details'\n",
        "  AND Source_country != 'International Waters'\n",
        "  AND Source_country != 'Australia (Re-imports)'\n",
        "GROUP BY\n",
        "  Source_country\n",
        "HAVING\n",
        "  SUM(`Total_oil_imports_ML`) > 0\n",
        "ORDER BY\n",
        "  total_oil_imports_ML DESC\n",
        "LIMIT 15"
      ]
    }
